var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"05:20 PM 미확인 함선, 통제실     \\n<color=#ffd34c>오르카, 에디, 제시카, 찰리</color>     \\nCSE Lv. 2     ","JPN":"05:20 PM 未確認艦船、制御室     \\n<color=#ffd34c>オルカ、エディー、ジェシカ、チャーリー</color>     \\nCSE Lv. 2     ","ENG":"05:20 PM Unknown Ship, Control Room     \\n<color=#ffd34c>Orca, Eddie, Jessica, Charlie</color>     \\nCSE Lv. 2     ","TWN":"下午17:20：未確認艦船，控制室\\n<color=#ffd34c>奧爾卡，艾迪，潔西卡，查理 </color> \\nCSE Lv. 2"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"아무래도 내가 잘못 들은 것 같은데. 다시 한 번 말해 주겠나?","JPN":"よく聞こえなかった。もう一度言ってくれるか？","ENG":"I don't think I heard you right. Could you repeat that?","TWN":"我想是我聽錯了，你可以再說一遍嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"쿨럭, 쿨럭......","JPN":"ゲホ、ゲホ……","ENG":"*Cough, cough*","TWN":"咳咳……咳咳……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그 나이에 벌써 가는귀가 먹었나 보군.","JPN":"耳が遠いのか？","ENG":"Aren’t you a little young to be going deaf already?","TWN":"你這個年紀就耳背了啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그럼 다시 친절히 설명해 드리지.","JPN":"だったら、もう一度丁寧に説明してやる。","ENG":"Alright then. I’ll walk you through it again like the sweet guy I am.","TWN":"那我就再好好地跟你說一遍。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"여기 있는 이터니움은 우리가 먹겠다.","JPN":"ここにあるエタニウムは俺たちがもらう。","ENG":"We’re taking all the Eternium here.","TWN":"這裡的永恆之金我全要了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"전부.","JPN":"全部な。","ENG":"All of it.","TWN":"全部！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"......제정신이 아니군.","JPN":"……正気じゃないな。","ENG":"You must be out of your mind...","TWN":"……你沒發燒吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"이봐, 나도 상도덕 같은 소릴 지껄일 생각은 없지만.......","JPN":"私も人のことは言えないが……","ENG":"Listen, I don't want to get into all that bull about work ethic or whatnot...","TWN":"我說，我也不想跟你談什麼商業道德之類的話……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"그래도 약속이란 게 있는데 너무한 거 아닌가?","JPN":"約束は守ってくれないと困る。","ENG":"But a promise is a promise. Don’t you think you're asking for too much?","TWN":"但我們有約在先，這是不是太過分了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"바로 그거지.","JPN":"それだ。","ENG":"That’s precisely my point.","TWN":"就是啊！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"서로가 원하는 걸 가진다. 그게 약속 아닌가?","JPN":"それぞれ求めているものを手に入れる。それが約束だろ？","ENG":"We each get what we want. Wasn’t that the promise?","TWN":"擁有彼此想要的東西，這不是每次都會發生的事情嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이터니움을 주겠다고 한 적은 없는데.","JPN":"俺はエタニウムをやるなんて、一言も言わなかったはずだ。","ENG":"I never agreed to give you the Eternium.","TWN":"況且我從沒說過要把永恆之金給你。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......쿨럭.","JPN":"……ゲホッ。","ENG":"*Cough*...","TWN":"……咳咳。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"이터니움이 바로 내가 원하는 거라고! 이 사기꾼아!","JPN":"私が求めているものはエタニウムなんだ！　この詐欺師が！","ENG":"The Eternium is what I want! You lying bastard!","TWN":"永恆之金就是我想要的東西！你這個騙子！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그걸 연기랍시고 하는 거라면 낙제점을 줄 수밖에 없는데.","JPN":"それが演技だとしたら、下手くそにもほどがあるな。","ENG":"If you're trying to put on an act, I’ve gotta say you made right career choice staying off the stage.","TWN":"如果這是演技的話，我會給你不及格。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"뭐라고?!","JPN":"何だと！？","ENG":"What?!","TWN":"你說什麼？！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......그럼 이렇게 하지.","JPN":"……じゃあ、こうしよう。","ENG":"Then let’s do this.","TWN":"……那不然這樣吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이터니움을 줄 테니 이 고물 함선은 우리가 가져가지.","JPN":"エタニウムはやるから、このボロ艦船は俺たちがもらう。","ENG":"I’ll give you the Eternium. We’ll keep this piece of junk ship.","TWN":"永恆之金給你，這艘破船我們拿走了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"어때? 설마 이 움직이지도 못하는 고철 덩어리가 사장님께서 원하시던 건 아니겠지?","JPN":"どうだ？　まさか、この鉄の塊が欲しいわけじゃないだろ？","ENG":"Well? This old hunk of metal wasn’t what you were after, was it?","TWN":"怎麼樣？ 這個動也動不了的破鐵塊，老闆不會也想要吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그것도 아까운가?","JPN":"それも嫌なのか？","ENG":"Oh, you don’t want to miss out on this either?","TWN":"這也不願意？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그럼 함선도 가져가라고. 고철로 뜯어서 팔면 몇 푼 더 받을지도 모르지.","JPN":"だったら艦船も譲ってやる。売り払えば少しは金になるかもな。","ENG":"Then you can have the ship too. I’m sure you can sell it as scrap metal for some pocket change.","TWN":"那你把艦船也拿走吧，賣廢鐵的話說不定還能多賺幾個錢呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"우린 그냥 데이터 뱅크만 뜯어서 갈 테니까.","JPN":"俺たちは、データバンクだけもらって行く。","ENG":"We’ll just take the data bank.","TWN":"我們把資料庫拿走就行了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"너 이 자식....... 어디까지 알고 있는 거냐?","JPN":"貴様……どこまで知ってるんだ？","ENG":"You bastard... How much do you exactly know about this?","TWN":"你這傢伙……到底知道多少？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......사실은 전혀 몰랐어. 완전히 깜박 속았지.","JPN":"……実は何も知らなかったんだ。完全に騙されたよ。","ENG":"To be honest, I didn’t know a thing. You had me completely fooled at first.","TWN":"……其實我什麼都不知道，我是完全被騙了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이중 속임수라면 많이 겪어 봤지만, 삼중 속임수라니.","JPN":"二重の罠ならまだしも、三重の罠を張るとはな。","ENG":"I mean, I’ve been double-crossed before, but triple?","TWN":"我經歷過很多次雙重騙局，但這次竟然是三重騙局。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"처음에는 그냥 단순히 주인 없는 이터니움을 싸게 회수하려는 속셈인 줄 알았지.","JPN":"最初はただ単に、持ち主のいないエタニウムを、安く回収するだけだと思っていた。","ENG":"At first I thought this was just a ploy to call dibs on a chunk of Eternium at a bargain price.","TWN":"剛開始我以為你只是單純地想低價回收無主的東西。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"하지만 이 함선을 보고 생각이 좀 바뀌었어.","JPN":"だが、この艦船を見て考えが変わった。","ENG":"But then I realized something when I saw this ship.","TWN":"但是看到這艘艦船後，我的想法就稍微改變了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이 배. 평범한 강습 수송함 같지만 무장 수준은 군용 이상이야.","JPN":"この艦船。一見、平凡な強襲揚陸艦のようだが、武装は軍用をはるかに上回る。","ENG":"This ship... It may look like an ordinary assault transport, but its armaments are beyond what you’ll find on the most powerful warships.","TWN":"這艘船，雖然看起來只是一艘普通的強襲運輸艦，但武裝水準卻超過了軍用標準。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"내구도도 말도 안 되게 튼튼하더군.","JPN":"耐久度も異様なまでに高かった。","ENG":"Not to mention how crazy sturdy the ship is.","TWN":"耐久度也非常好。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"버려진 지 한참은 지난 것 같은데 아직 기능이 살아 있는 걸 보면 말이지.","JPN":"捨てられてからしばらく経つのに、まだ機能が生きてたからな。","ENG":"It seems to have been abandoned for years, but the ship still manages to function.","TWN":"雖然被拋棄了很久，但功能都還能運轉。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"아무도 관심을 가지지 않는 CSE 레벨 2짜리 동네에 이터니움 노다지가 굴러다닌다는 것도 이상한데...","JPN":"誰も興味を示さないCSEレベル2の区域に、エタニウムがゴロゴロ転がってるのも変だが……","ENG":"It’s weird enough that there’s an Eternium jackpot sitting in a CSE Level 2 zone that no one could care less about...","TWN":"然後在完全沒有人在意，CSE等級為2的區域裡到處都是永恆之金，這點也很奇怪。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"거기에 군용 클래스의 위장함이 떡 하니 버려져 있다고?","JPN":"そこに軍用クラスの偽装艦まで捨てられてるんだぞ？","ENG":"And now you're telling me there’s a military-class ship disguised as a transporter there too?","TWN":"竟然會有一艘軍用級的偽裝艦船被扔在這裡？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그런 걸 우연이라고 생각한다면 어깨 위에 달린 게 모자걸이라고 해도 할말이 없지.","JPN":"これを偶然だって言うやつがいるなら、そいつは救いようのないバカだ。","ENG":"Only a fool would believe this is all just a coincidence.","TWN":"如果你認為這只是一個巧合，那我無話可說。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"좋아...... 머리 좋은 친구.","JPN":"わかった……君は実に賢いな。","ENG":"Okay... Wise guy.","TWN":"好吧……真是個聰明的傢伙。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"협상을 해 보자고. 뭘 원하나?","JPN":"交渉をしよう。要求は何だ？","ENG":"Let’s make a deal. What do you want?","TWN":"讓我們來協商一下吧，你想要什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"말했듯이, 쿨럭...... 쿨럭......","JPN":"言っただろ。ゲホ……ゲホ……","ENG":"Like I said... \\"Cough!\\" *Cough!*","TWN":"就像我剛才說的，咳咳……咳咳……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......이터니움 전부.","JPN":"……エタニウム、全部だ。","ENG":"All of this Eternium.","TWN":"……永恆之金全部？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"대신, 함의 정보는 고스란히 넘겨 주지.","JPN":"代わりに、艦船の情報をすべて渡す。","ENG":"Instead, you get all the data from the ship.","TWN":"同時，我會把情報原封不動地交給你。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"제기랄, 똑똑한 친구가 너무 욕심부리다간 제 명대로 살기 어렵단 사실은 왜 모르지?","JPN":"クソ、賢い割に頭が回らないようだな。欲張りすぎると長生きできないぞ？","ENG":"For a smart guy, you fail to see that getting too greedy will get you killed.","TWN":"天殺的，你沒聽過“太貪心的人活不長。”這句話嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"네 말대로 우린 그 함이 필요해.","JPN":"君の言う通り、我々にはその艦船が必要だ。","ENG":"Like you said, we need that ship.","TWN":"就像你說的一樣，我們需要那艘船。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"정확한 위치와 접근 루트를 알아야 했어.","JPN":"正確な位置とルートを調べる必要があった。","ENG":"We needed to know the exact location and access route.","TWN":"我們必須要知道準確的位置和路徑。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"그래서 네놈들을 보낸 거지.","JPN":"だから、君たちを向かわせた。","ENG":"That’s why we sent you.","TWN":"所以我才派你們去的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"하지만 그 함에 실려 있는 이터니움도 필요해!","JPN":"だが、その艦船のエタニウムも必要だ！","ENG":"But we also need the Eternium on board!","TWN":"但是我們也需要那裡面的永恆之金！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"그건 그냥 포기하기엔 너무 큰 물건이야.","JPN":"諦めるには価値があり過ぎる。","ENG":"It’s too much to just give away.","TWN":"直接放棄的話虧太大了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"......그러니 이렇게 하지.","JPN":"……だから、こうしよう。","ENG":"So let’s do this instead.","TWN":"……那就這樣吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"25%를 주겠다. 그 정도로 만족해. 큰 돈이잖아?","JPN":"25％をやる。それで満足しろ。十分な額だろ？","ENG":"I’ll give you 25%. That ought to be good enough for you, no? I mean, it’s still a lot of money.","TWN":"給你25%，滿意了吧？這應該不是小錢吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......75%.","JPN":"……75％。","ENG":"......75%.","TWN":"……75%。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"제기랄, 30%!","JPN":"クソッ、30％。","ENG":"Damn it... 30%","TWN":"該死，30！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"50%.","JPN":"50％。","ENG":"50%.","TWN":"50%。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"더 이상은 안 돼. 이것도 꽤나 손해 보는 금액이라고.","JPN":"これ以上は無理だ。これでもかなり損してるんだ。","ENG":"That’s my final offer. I’m still losing out a lot with this.","TWN":"不能再讓步了，這樣我們損失已經很大了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"악마 같은 자식.......","JPN":"悪魔め……","ENG":"You son of a devil...","TWN":"真的是跟惡魔一樣的傢伙……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"좋아. 50%로 하지. 구조대를 보내겠다.","JPN":"わかった、50％にしよう。救助隊を送る。","ENG":"Fine. 50% it is. I’ll send in an extraction team.","TWN":"好，那就50%。我會派救援隊過去。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"하지만 명심하라고.","JPN":"だが、覚えておけ。","ENG":"But remember.","TWN":"但給我聽好了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"조금이라도 장난질을 하는 순간, 네놈들은 다 죽은 목숨이야.","JPN":"私を騙すと君たちの命はないぞ。","ENG":"Any funny business, and you're all dead.","TWN":"要是你們敢耍花樣，我會讓你們死無葬身之地的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"좋아. 우리 위치와 접근 경로 데이터를 보내 주지. 잘 받으라고.","JPN":"ああ。俺たちの位置とここまでのルートのデータを送る。しっかり受け取れ。","ENG":"Deal. I’ll send you our location and access route information. Don’t miss it.","TWN":"非常好。那我把我們的位置和路徑情報發給你，好好接收吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"협상은 잘됐어?","JPN":"交渉はどうなった？","ENG":"Did the negotiation go well?","TWN":"協商還順利嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그래. 구조대를 보낸다는군. 이터니움의 절반은 우리 몫으로 인정하고 말이지.","JPN":"うまくいった。救助隊を送るそうだ。エタニウムの半分は俺たちの分だ。","ENG":"Yeah. They’re sending us an extraction team. And they recognize that half the Eternium is ours.","TWN":"是啊。他說會派遣救援隊，又說會給我們一半的永恆之金。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"좋았어!! 이제 난 부자다! ","JPN":"よっしゃ！！　俺は金持ちだ！","ENG":"Yes!! I’m rich now!! ","TWN":"太好了！！現在我是有錢人了！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"크하하하! 돌아가면 당장 그놈 얼굴에 사표부터 던질 거야!","JPN":"がははは！　戻ったら、あいつの顔に辞表を叩きつけてやる！","ENG":"Bwahaha! The first thing I’ll do when I get back is quit this blasted job!","TWN":"哈哈哈！回去後我就立刻把辭職信扔在老闆臉上！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"아...... 멍청한 새끼.","JPN":"はあ……本当にバカね。","ENG":"Oh... You idiot.","TWN":"哈……這個傻小子。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"후...... 그래도 머리 돌아가는 놈이 하나는 있어 다행이군. 쿨럭...... 쿨럭......","JPN":"ふう……頭の回転が速いやつが一人はいてよかった。ゲホ……ゲホ……","ENG":"*Sigh...* Well, I’m glad at least one of you are sharp enough to catch on. *Cough!* *Cough!*","TWN":"呼……還好這裡有一個有腦子的傢伙。\\n咳咳……咳咳……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"어? 뭐? 뭔가 기분 나쁜데. 그게 무슨 뜻이야?","JPN":"は？　何だ？　何か腹立つな。それ、どういう意味だ？","ENG":"Huh? What? That sounded like a diss. What the hell is that supposed to mean?!","TWN":"啊，什麼？聽起來有些不妙，你這是什麼意思？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"잘 생각해 봐라.","JPN":"よく考えてみてよ。","ENG":"Think about it.","TWN":"你好好動動腦袋想一想。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그놈이 뭐하러 우리에게 이터니움을 절반씩이나 주겠어?","JPN":"雇用主が私たちに、半分もエタニウムをくれるわけないじゃない。","ENG":"Why would he give us half of the Eternium?","TWN":"那傢伙為什麼要給我們一半的永恆之金？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"구조대처럼 생긴 암살대원을 보내서 우리 머리통에 납 탄 몇 알만 박으면 모조리 자기 것일 텐데.","JPN":"救助隊のふりをした暗殺隊を送って、私たちを殺せば全部自分のものになるのに。","ENG":"He could just send an assassin posing as an extraction crew and put a few slugs in our heads. Then he gets to keep all of it.","TWN":"如果派一個偽裝成救援隊的暗殺部隊把我們全部殺了，永恆之金不就都是他們的嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그, 그럼 다른 회사에 연락을 하면......","JPN":"な、なら、他の会社に連絡をすれば……","ENG":"T-then we could contact a different company...","TWN":"那、那我們聯絡其他公司……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"놈들은 아마 군 관계자들일 거다.","JPN":"そいつらは、たぶん軍の関係者だ。","ENG":"They’re probably associates of the military.","TWN":"他們應該是軍隊的相關人員。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"어디 소속인지는 모르겠지만 아마 지금쯤 이 근처 전파 통신은 모조리 막혔을 거야.","JPN":"所属はわからないが、今頃この辺りの電波はすべて遮断されたはずだ。","ENG":"I wouldn’t know which unit, exactly, but I bet all the comms around here are jammed by now.","TWN":"雖然不知道是哪裡的軍隊，但現在這附近的電波通訊應該都被封鎖了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그리고...... 이건 내 추측이지만, 아마 이 전함을 회수하는 것도 놈들의 최종 목적은 아닐 거라고 본다.","JPN":"あと……これは俺の考えだが、やつらの最終目的はこの艦船の回収じゃない。","ENG":"And... This is just a gut feeling, but I don’t think this ship is their final objective either.","TWN":"還有……這雖然是我的推測，但我認為回收這艘戰艦並不是他們的最終目的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"뭐? 여기에 또 뭔가가 더 있어?","JPN":"え？まだ何かあるの？","ENG":"Huh? There’s something more to this?","TWN":"什麼？還有其他目的？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이건 정말로 추측이지만......","JPN":"これは、本当に単なる推測だが……","ENG":"This is just a wild guess, really...","TWN":"雖然這真的只是推測……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"여기에 도착하기까지 만난 침식체 놈들의 행동을 기억하나?","JPN":"ここに来るまで戦った侵食体の行動を覚えてるか？","ENG":"But remember how those C.O.'s we met on the way here were behaving?","TWN":"還記得在到達這裡之前，我們遇到的侵蝕體嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"They were...","TWN":"這……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"분명 굉장히 지능적이었어.","JPN":"すごく賢かったわね。","ENG":"Clearly intelligent.","TWN":"他們確實很聰明。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그리고 조직적이지.","JPN":"しかも、組織的だ。","ENG":"And organized.","TWN":"也很有組織性。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이면세계에서 직접 만나는 고위 침식체들은 그런 경우도 있다고 하지만.......","JPN":"カウンターサイドで直接遭遇する高位侵食体の場合、そういうこともあるらしいが……","ENG":"I mean, I've heard of some high ranking C.O. in the Counterside can be like that...","TWN":"雖然說在異界裡也有可能直接遇到高等的侵蝕體……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"현실 세계, 그것도 이런 저준위 침식지대에서 그런 행동을 하는 놈들이 있다는 건 들어본 적도 없어.","JPN":"ノーマルサイド、しかもこんなレベルの低い侵食地帯で、そんな行動をするやつらがいるなんて、聞いたこともない。","ENG":"But it's unheard of in the Normalside, especially a Corrupted Area with a relatively low CSE level.","TWN":"但在現實世界裡，而且還是這麼低等的侵蝕地帶，居然會有這種智慧侵蝕體存在，這我聽都沒聽過。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"나도 그래.","JPN":"私も聞いたことないわ。","ENG":"Yeah, I’ve never heard of it either.","TWN":"我也這麼認為。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"가능성은 두 가지다.","JPN":"可能性は二つだ。","ENG":"So there are two possibilities.","TWN":"這有兩種可能性。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"하나는 여기에 아무도 본 적 없는 신종이 그냥 우연히 나타났거나.","JPN":"一つは、誰も見たことのない新種が、偶然ここに現れた。","ENG":"First, an entirely new type of C.O. just happened to appear here.","TWN":"一種是在這裡偶然出現了誰都沒見過的新品種。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"아니면......","JPN":"もしくは……","ENG":"Or...","TWN":"還是……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"누군가가 의도를 가지고 만들어 낸 것?","JPN":"誰かが意図的に作り出した……？","ENG":"Someone made it deliberately?","TWN":"是誰故意製造出來的？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"빙고.","JPN":"ビンゴだ。","ENG":"Bingo.","TWN":"BINGO。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"어쩌면...... 이건 테스트일지도 몰라.","JPN":"もしかしたら……これは、テストかもしれない。","ENG":"Maybe... This is just a test.","TWN":"也許……這是一場實驗。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"놈들이 정말로 원하는 건......","JPN":"やつらが本当に求めているのは……","ENG":"What they really want is...","TWN":"他們真正想要的是……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>우리는 구조부대다!</color>","JPN":"<color=#ffd34c>こちらは救助隊だ！</color>","ENG":"<color=#ffd34c>We're the extraction team!</color>","TWN":"<color=#ffd34c>我們是救援部隊！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이봐, 친구들. 데리러 왔으니 빨리 나오라고.</color>","JPN":"<color=#ffd34c>おい、迎えに来たぞ。早く出てこい。</color>","ENG":"<color=#ffd34c>Hey, pals. We've come to get you. So get out here.</color>","TWN":"<color=#ffd34c>嘿，朋友，我們來接你們了，快出來。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>집에 갈 시간이다!</color>","JPN":"<color=#ffd34c>家に帰る時間だぞ！</color>","ENG":"<color=#ffd34c>It’s time to go home!</color>","TWN":"<color=#ffd34c>回家時間到了！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......빠르군.","JPN":"……早いな。","ENG":"That was quick.","TWN":"……好快啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"빨라도 너무 빠른데?","JPN":"ちょっと早すぎない？","ENG":"Too quick to be true.","TWN":"也太快了吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"내 생각이 맞는다면 놈들은 우릴 생포하는 게 목적일 거다.","JPN":"俺の考えが間違ってなければ、やつらは俺たちを生きたまま捕らえるつもりだ。","ENG":"If my guess is right, they're probably going to try to capture us alive.","TWN":"如果我沒猜錯的話，那群傢伙的目的是要活捉我們。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"너흰 어떡할 거지?","JPN":"お前らはどうする？","ENG":"What are you guys going to do?","TWN":"你們想要怎麼做？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"빌어 처먹을 놈들이! 겨우겨우 찾아온 인생 역전의 기회라고!","JPN":"ちくしょう！　やっと手に入れたチャンスなんだ！","ENG":"Those bastards! This is the opportunity of my lifetime!","TWN":"去他們的！我好不容易有了逆轉人生的機會！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"호락호락 잡혀줄 것 같냐?!","JPN":"捕まってたまるか！","ENG":"I ain’t gonna let them take me so easily!","TWN":"我才不想被他們抓走。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"넌?","JPN":"お前は？","ENG":"And you?","TWN":"妳呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"나 역시. 저런 개자식들 손에 놀아나려고 아득바득 기어 온 게 아니라고.","JPN":"私も一緒よ。あんなやつらに弄ばれるために、ここまで生き延びたわけじゃないわ。","ENG":"Same here. I didn’t work my ass off just so those bastards can toy with me.","TWN":"我為了不讓那些狗崽子們玩弄，才拼命爬過來的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"좋아. 의견은 일치된 것 같군.","JPN":"よし。意見が一致したな。","ENG":"Very well. Looks like we're all in agreement.","TWN":"很好，所有人意見一致。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"오르카.","JPN":"オルカ。","ENG":"Orca.","TWN":"奧爾卡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......응.","JPN":"……うん。","ENG":"Yeah.","TWN":"……嗯。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"네가 우리의 에이스 카드다.","JPN":"お前が俺たちのエースだ。","ENG":"You’re the ace up our sleeve.","TWN":"妳是我們的王牌。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"놈들은 아직 오르카의 전력을 몰라.","JPN":"やつらは、オルカの戦闘力を知らない。","ENG":"Those guys don’t know what Orca's capable of yet.","TWN":"他們還不知道奧爾卡的戰鬥能力。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"놈들을 함내로 유인한 후, 오르카를 중심으로 단숨에 뚫고 나가서 헬기를 탈취한다.","JPN":"やつらを艦内におびき寄せた後、オルカを中心に一気に突破してヘリコプターを乗っ取る。","ENG":"We’ll lure them into the ship then break through with Orca on point. Once we're outside, we’ll take their helicopter.","TWN":"我們把敵人引誘到船艦裡面後，以奧爾卡為中心，一口氣衝出去搶走直升機。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"할 수 있겠나?","JPN":"できるか？","ENG":"Think you can do it?","TWN":"能做到嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"나는...... 침식체를 죽여...... 사람은...... 관심 없어......","JPN":"オルカは……侵食体を殺す……人は……興味ない……","ENG":"I... kill Corrupted Objects... I’m not... interested in people.","TWN":"我只……殺侵蝕體……對人……不感興趣……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그건 <color=#ffd34c>오르카</color>의 의지겠지.","JPN":"それは<color=#ffd34c>オルカ</color>の意志だ。","ENG":"That’s the <color=#ffd34c>Orca</color> speaking.","TWN":"那是 <color=#ffd34c>奧爾卡</color>的意志吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"하지만 너는 어떻지?","JPN":"だが、お前はどうだ？","ENG":"But what about you?","TWN":"但妳的想法呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......나?","JPN":"……私？","ENG":"Me?","TWN":"……我？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"놈들은 아마 널 사로잡으려 할 거다.","JPN":"多分あいつらは、お前を捕えようとするはずだ。","ENG":"They’ll probably try to capture you alive.","TWN":"那群傢伙很可能也想要抓住妳。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"잡아서 뭘 할진 모르겠지만 좋은 일은 아니겠지.","JPN":"何をするつもりかわからないが、きっといいことじゃない。","ENG":"I don’t know what they’ll do to you afterwards, but it can’t be good.","TWN":"雖然不知道他們抓妳要做什麼，但絕對不會是什麼好事。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"오르카는...... 뭐, 상관없겠지.","JPN":"オルカは……まあ、関係ないだろ。","ENG":"As for Orca... Well, it probably doesn’t care.","TWN":"奧爾卡的話……嗯，他無所謂吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"시간은 좀 걸리겠지만 언젠가는 다시 다른 숙주를 찾아서 침식체를 죽이러 떠나면 될 테니까.","JPN":"多少時間がかかっても、また他の宿主を見つけて侵食体を殺せばいいからな。","ENG":"It might take some time but it could always find another host to keep killing C.O.'s with.","TWN":"雖然需要耗費一些時間，但總有一天他會再去找其他的宿主殘殺侵蝕體。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"하지만 넌 어때?","JPN":"だが、お前は？","ENG":"But what about you?","TWN":"但是妳呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"넌 어쩌고 싶지?","JPN":"どうしたい？","ENG":"What do you want to do?","TWN":"妳要怎麼做？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이대로 잡혀서 모든 자유를 잃고 네 본능의 꼭두각시가 되는 것으로 만족하나?","JPN":"このまま捕まって自由を奪われ、本能に操られてもいいのか？","ENG":"Do you want to be captured and lose your freedom? Are you satisfied with remaining a slave to your instincts?","TWN":"就這樣被抓住，失去所有自由，成為妳本能的人偶……這樣妳願意嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"네 의지를 말해 봐!","JPN":"お前の意志は何だ！","ENG":"Tell me what YOU want!","TWN":"說說妳的意志吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"나는......","JPN":"私……","ENG":"I...","TWN":"我……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"나는, 기억을 찾고 싶어!","JPN":"私は、記憶を取り戻したい！","ENG":"I want to get my memories back!","TWN":"我，我想找回記憶！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"이 속박에서 자유로워지고 싶어!","JPN":"この束縛から自由になりたい！","ENG":"I want to be freed from this bondage!","TWN":"我想從束縛中解放出來！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그때까지는......","JPN":"その時までは……","ENG":"Until then...","TWN":"在這之前……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그때까지는, 죽고 싶지 않아!","JPN":"その時までは、死にたくない！","ENG":"Until then, I don’t want to die!","TWN":"在這之前，我還不想死！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"좋아. 휘둘리지 말고 꿋꿋이 버티는 거다.","JPN":"よし。振り回されずに、しっかり耐えろ。","ENG":"Good. Hang on to that thought, no matter what.","TWN":"很好，不要動搖，要堅守妳的意志。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"지금의 기억을 잊지 마.","JPN":"今の記憶を忘れるな。","ENG":"Don’t forget this.","TWN":"不要忘記這一刻的記憶。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"함내 보안 시스템에 침입자가 잡혔어!","JPN":"艦内のセキュリティシステムが侵入者を感知した！","ENG":"The ship’s security system picked up on intruders!","TWN":"艦內的保全系統偵測到了入侵者。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L16_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"놈들이 진입했군. 환영파티를 해 주자고, 친구들.","JPN":"やつらが来たようだ。派手に出迎えるぞ、みんな。","ENG":"They’re in. Let’s throw them a welcome party then.","TWN":"他們進來了，給他們開個歡迎派對吧，朋友們。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};